142	          is_vsmul = 1'b0;
143	        end
144	        VMULH : begin
145	          mul_src2 = mul_uop_vs2_data;
146	          mul_src1 = mul_uop_vs1_data;
147	          mul_src2_is_signed = 1'b1;
148	          mul_src1_is_signed = 1'b1;
149	          mul_is_widen = 1'b0;
150	          mul_keep_low_bits = 1'b0;
151	          is_vsmul = 1'b0;
152	        end
153	        VMULHU : begin
154	          mul_src2 = mul_uop_vs2_data;
155	          mul_src1 = mul_uop_vs1_data;
156	          mul_src2_is_signed = 1'b0;
157	          mul_src1_is_signed = 1'b0;
158	          mul_is_widen = 1'b0;
159	          mul_keep_low_bits = 1'b0;
160	          is_vsmul = 1'b0;
161	        end
