181	          mul_src2 = {64'b0,mul_uop_vs2_data[mul_uop_index*64 +: 64]};
182	          mul_src1 = {64'b0,mul_uop_vs1_data[mul_uop_index*64 +: 64]};
183	          mul_src2_is_signed = 1'b0;
184	          mul_src1_is_signed = 1'b0;
185	          mul_is_widen = 1'b1;
186	          mul_keep_low_bits = 1'b0;//if widen, keep_low doesnt matter
187	          is_vsmul = 1'b0;
188	        end
189	        VWMULSU : begin
190	          mul_src2 = {64'b0,mul_uop_vs2_data[mul_uop_index*64 +: 64]};
191	          mul_src1 = {64'b0,mul_uop_vs1_data[mul_uop_index*64 +: 64]};
192	          mul_src2_is_signed = 1'b1;
193	          mul_src1_is_signed = 1'b0;
194	          mul_is_widen = 1'b1;
195	          mul_keep_low_bits = 1'b0;//if widen, keep_low doesnt matter
