265	        end
266	        VWMULSU : begin
267	          mul_src2 = {64'b0,mul_uop_vs2_data[mul_uop_index*64 +: 64]};
268	          mul_src1 = {{(`VLEN-`XLEN){mul_uop_rs1_data[`XLEN-1]&&mul_src1_is_signed}},mul_uop_rs1_data}; //use rs1
269	          mul_src2_is_signed = 1'b1;
270	          mul_src1_is_signed = 1'b0;
271	          mul_is_widen = 1'b1;
272	          mul_keep_low_bits = 1'b0;//if widen, keep_low doesnt matter
273	          is_vsmul = 1'b0;
274	        end
275	        default : begin //default use VMUL
276	          mul_src2 = mul_uop_vs2_data;
277	          mul_src1 = {{(`VLEN-`XLEN){mul_uop_rs1_data[`XLEN-1]&&mul_src1_is_signed}},mul_uop_rs1_data}; //use rs1
278	          mul_src2_is_signed = 1'b1;
279	          mul_src1_is_signed = 1'b1;
280	          mul_is_widen = 1'b0;
281	          mul_keep_low_bits = 1'b1;
282	          is_vsmul = 1'b0;
283	        end//end default
284	      endcase
285	    end//end OPMVX
286	    {1'b1,OPIVV} : begin
287	      is_vv = 1'b1;
288	      case (mul_uop_funct6) 
289	        VSMUL_VMVNRR : begin
290	          mul_src2 = mul_uop_vs2_data;
291	          mul_src1 = mul_uop_vs1_data;
292	          mul_src2_is_signed = 1'b1;
293	          mul_src1_is_signed = 1'b1;
294	          mul_is_widen = 1'b0;
295	          mul_keep_low_bits = 1'b0;
296	          is_vsmul = 1'b1;
297	        end
298	        default : begin //currently put default the same as vsmul
299	          mul_src2 = mul_uop_vs2_data;
300	          mul_src1 = mul_uop_vs1_data;
301	          mul_src2_is_signed = 1'b1;
302	          mul_src1_is_signed = 1'b1;
303	          mul_is_widen = 1'b0;
304	          mul_keep_low_bits = 1'b0;
305	          is_vsmul = 1'b1;
306	        end//end default
307	      endcase//end funct6
308	    end//end OPIVV
309	    {1'b1,OPIVX} : begin
310	      is_vv = 1'b0;
311	      case (mul_uop_funct6) 
312	        VSMUL_VMVNRR : begin
313	          mul_src2 = mul_uop_vs2_data;
314	          mul_src1 = {{(`VLEN-`XLEN){mul_uop_rs1_data[`XLEN-1]&&mul_src1_is_signed}},mul_uop_rs1_data}; //use rs1
315	          mul_src2_is_signed = 1'b1;
316	          mul_src1_is_signed = 1'b1;
317	          mul_is_widen = 1'b0;
318	          mul_keep_low_bits = 1'b0;
319	          is_vsmul = 1'b1;
320	        end
321	        default : begin //currently put default the same as vsmul
322	          mul_src2 = mul_uop_vs2_data;
323	          mul_src1 = {{(`VLEN-`XLEN){mul_uop_rs1_data[`XLEN-1]&&mul_src1_is_signed}},mul_uop_rs1_data}; //use rs1
324	          mul_src2_is_signed = 1'b1;
325	          mul_src1_is_signed = 1'b1;
326	          mul_is_widen = 1'b0;
327	          mul_keep_low_bits = 1'b0;
328	          is_vsmul = 1'b1;
329	        end//end default
330	      endcase//end funct6
331	    end//end OPIVX
332	    default : begin
333	      is_vv = 1'b1;
334	      mul_src2 = `VLEN'b0;
335	      mul_src1 = `VLEN'b0;
336	      mul_src2_is_signed = 1'b0;
337	      mul_src1_is_signed = 1'b0;
338	      mul_is_widen = 1'b0;
339	      mul_keep_low_bits = 1'b0;
340	      is_vsmul = 1'b0;
341	    end//end default
342	  endcase//end funct3
343	end
344	
345	// Before using MUL alu, 
346	//  1.group sub-elements' sign bit
347	// (TODO) let input is 0 when not use that EU
348	always@(*) begin
349	  case (mul_top_vs_eew) 
350	    EEW8 : begin
351	      mul_src2_mux = mul_src2;
352	      mul_src1_mux = is_vv ? mul_src1 : {16{mul_src1[7:0]}};
353	      mul_src2_is_signed_extend = {16{mul_src2_is_signed}};
354	      mul_src1_is_signed_extend = {16{mul_src1_is_signed}};
355	    end//end eew8
356	    EEW16 : begin
357	      mul_src2_mux = mul_src2;
358	      mul_src1_mux = is_vv ? mul_src1 : {8{mul_src1[15:0]}};
359	      mul_src2_is_signed_extend = {8{mul_src2_is_signed,1'b0}};
360	      mul_src1_is_signed_extend = {8{mul_src1_is_signed,1'b0}};
361	    end//end eew16
362	    EEW32 : begin
363	      mul_src2_mux = mul_src2;
364	      mul_src1_mux = is_vv ? mul_src1 : {4{mul_src1[31:0]}};
365	      mul_src2_is_signed_extend = {4{mul_src2_is_signed,3'b0}};
366	      mul_src1_is_signed_extend = {4{mul_src1_is_signed,3'b0}};
367	    end//end eew32
368	    default : begin //default use eew8
369	      mul_src2_mux = mul_src2;
370	      mul_src1_mux = is_vv ? mul_src1 : {16{mul_src1[7:0]}};
371	      mul_src2_is_signed_extend = {16{mul_src2_is_signed}};
372	      mul_src1_is_signed_extend = {16{mul_src1_is_signed}};
373	    end//end default
374	  endcase
375	end
376	
377	// Before MUL, always depart 128 bits into 16x8 sub-elements
378	always@(*) begin
379	  for (i=0; i<16; i=i+1) begin
380	      mul8_in0[i] = mul_src2_mux[i*8 +: 8];
381	      mul8_in1[i] = mul_src1_mux[i*8 +: 8];
382	      mul8_in0_is_signed[i] = mul_src2_is_signed_extend[i];
383	      mul8_in1_is_signed[i] = mul_src1_is_signed_extend[i];
384	  end
385	end
386	
387	// MUL alus with d1_reg
388	//  in a 4 of 4x4 tiled way for instantiation
389	generate 
390	  for (z=0; z<4; z=z+1) begin 
391	    for (x=0; x<4; x=x+1) begin
392	      for (y=0; y<4; y=y+1) begin
393	        rvv_backend_mul_unit_mul8 u_mul8 (
394	          .res(mul8_out[z*16+y*4+x]), //16bit out
395	          .src0(mul8_in0[z*4+x]), 
396	          .src0_is_signed(mul8_in0_is_signed[z*4+x]),
397	          .src1(mul8_in1[z*4+y]), 
398	          .src1_is_signed(mul8_in1_is_signed[z*4+y]));
399	
400	        edff #(.T(logic [16-1:0])) u_mul8_delay (
401	          .q(mul8_out_d1[z*16+y*4+x]), 
402	          .clk(clk), 
403	          .rst_n(rst_n), 
404	          .e(mul_stg0_data_en),
405	          .d(mul8_out[z*16+y*4+x]));
406	      end
407	    end
408	  end
409	endgenerate
410	
411	edff #(.T(logic)) u_valid_delay (.q(rs2mul_uop_valid_d1), .clk(clk), .rst_n(rst_n), .e(mul_stg0_vld_en), .d(rs2mul_uop_valid));
412	edff #(.T(logic)) u_src2_is_signed_delay (.q(mul_src2_is_signed_d1), .clk(clk), .rst_n(rst_n), .e(mul_stg0_data_en), .d(mul_src2_is_signed));
413	edff #(.T(logic)) u_src1_is_signed_delay (.q(mul_src1_is_signed_d1), .clk(clk), .rst_n(rst_n), .e(mul_stg0_data_en), .d(mul_src1_is_signed));
414	edff #(.T(logic)) u_is_widen_delay (.q(mul_is_widen_d1), .clk(clk), .rst_n(rst_n), .e(mul_stg0_data_en), .d(mul_is_widen));
415	edff #(.T(logic)) u_keep_low_bits_delay (.q(mul_keep_low_bits_d1), .clk(clk), .rst_n(rst_n), .e(mul_stg0_data_en), .d(mul_keep_low_bits));
416	edff #(.T(logic)) u_is_vsmul_delay (.q(is_vsmul_d1), .clk(clk), .rst_n(rst_n), .e(mul_stg0_data_en), .d(is_vsmul));
417	edff #(.T(logic [2-1:0])) u_xrm_delay (.q(mul_uop_xrm_d1), .clk(clk), .rst_n(rst_n), .e(mul_stg0_data_en), .d(mul_uop_xrm));
418	edff #(.T(logic [3-1:0])) u_eew_delay (.q(mul_top_vs_eew_d1), .clk(clk), .rst_n(rst_n), .e(mul_stg0_data_en), .d(mul_top_vs_eew));
419	
420	edff #(.T(logic [`ROB_DEPTH_WIDTH-1:0])) u_rob_entry_delay (.q(mul_uop_rob_entry_d1), .clk(clk), .rst_n(rst_n), .e(mul_stg0_data_en), .d(mul_uop_rob_entry));
421	
422	`ifdef TB_SUPPORT
423	edff #(.T(logic [`PC_WIDTH-1:0])) u_PC_delay (.q(mul_uop_pc_d1), .clk(clk), .rst_n(rst_n), .e(mul_stg0_data_en), .d(mul_uop_pc));
424	`endif
425	
426	/////////////////////////////////////////////////
427	///////Enter d1_stage ///////////////////////////
428	/////////////////////////////////////////////////
429	
430	// After MUL, calculte eew8, eew16, eew32 results
431	// Here we have a ([15:0] [63:0] mul8_out_d1)
432	//eew8
433	//full rslt is 16bit
434	always@(*) begin
435	  for (i=0; i<4; i=i+1) begin //z
436	    for (j=0; j<4; j=j+1) begin //x
437	        mul_rslt_full_eew8_d1[i*4+j] = mul8_out_d1[i*16+j*5];
438	        mul_rslt_eew8_widen_d1[16*(i*4+j) +: 16] = mul_rslt_full_eew8_d1[i*4+j];//widen, and convert to [255:0]
439	        mul_rslt_eew8_no_widen_d1[8*(i*4+j) +: 8] = mul_keep_low_bits_d1 ? mul_rslt_full_eew8_d1[i*4+j][7:0] : mul_rslt_full_eew8_d1[i*4+j][15:8];
440	        //Below are for rounding mul (vsmul.vv, vsmul.vx)
441	        //right shift bit is 7 not 8 !
442	        //(TODO) Improve to make this readable
443	        vsmul_round_incr_eew8_d1[i*4+j] = mul_uop_xrm_d1==2'd3 ? !mul_rslt_full_eew8_d1[i*4+j][7] && (|mul_rslt_full_eew8_d1[i*4+j][6:0]) : //ROD
444	                                          mul_uop_xrm_d1==2'd2 ? 1'b0  : //RDN
445	                                          mul_uop_xrm_d1==2'd1 ? mul_rslt_full_eew8_d1[i*4+j][6] && (|(mul_rslt_full_eew8_d1[i*4+j][5:0]) || mul_rslt_full_eew8_d1[i*4+j][7]) : //RNE
446	                                                                 mul_rslt_full_eew8_d1[i*4+j][6]; //RNU
447	        vsmul_rslt_eew8_d1[8*(i*4+j) +:8]= mul_rslt_full_eew8_d1[i*4+j][15:14] == 2'b01 ? 8'h7f : //saturate
448	                                                                                      mul_rslt_full_eew8_d1[i*4+j][7+:8] + {7'b0,vsmul_round_incr_eew8_d1[i*4+j]};//right shift 7bit then +"1"
449	        vsmul_sat_eew8_d1[i*4+j] = mul_rslt_full_eew8_d1[i*4+j][15:14] == 2'b01;
450	    end
451	  end
452	end
453	assign mul_rslt_eew8_d1 = is_vsmul_d1     ? vsmul_rslt_eew8_d1 : //vsmul
454	                          mul_is_widen_d1 ? mul_rslt_eew8_widen_d1[`VLEN-1:0] : //widen
455	                                            mul_rslt_eew8_no_widen_d1; //normal
456	assign update_vxsat_eew8_d1 = vsmul_sat_eew8_d1;
457	//eew16
458	//full rslt is 32bit
459	always@(*) begin
460	  for (i=0; i<4; i=i+1) begin //z
461	    for (j=0; j<2; j=j+1) begin //x
462	      mul_rslt_full_eew16_d1[i*2+j] = {mul8_out_d1[i*16+j*10+5],16'b0} + 
463	                                   {{8{mul8_out_d1[i*16+j*10+4][15]&&mul_src1_is_signed_d1}},mul8_out_d1[i*16+j*10+4],8'b0} + 
464	                                   {{8{mul8_out_d1[i*16+j*10+1][15]&&mul_src2_is_signed_d1}},mul8_out_d1[i*16+j*10+1],8'b0} + 
465	                                   {16'b0,mul8_out_d1[i*16+j*10]};
466	      mul_rslt_eew16_widen_d1[32*(i*2+j) +: 32] = mul_rslt_full_eew16_d1[i*2+j];//widen, and convert to [255:0]
467	      mul_rslt_eew16_no_widen_d1[16*(i*2+j) +: 16] = mul_keep_low_bits_d1 ? mul_rslt_full_eew16_d1[i*2+j][15:0] : mul_rslt_full_eew16_d1[i*2+j][31:16];
468	      //Below are for rounding mul (vsmul.vv, vsmul.vx)
469	      //right shift bit is 16-1=15 not 16 !
470	      //(TODO) Improve to make this readable
471	      vsmul_round_incr_eew16_d1[i*2+j] = mul_uop_xrm_d1==2'd3 ? !mul_rslt_full_eew16_d1[i*2+j][15] && (|mul_rslt_full_eew16_d1[i*2+j][14:0]) : //ROD
472	                                         mul_uop_xrm_d1==2'd2 ? 1'b0  : //RDN
473	                                         mul_uop_xrm_d1==2'd1 ? mul_rslt_full_eew16_d1[i*2+j][14] && (|(mul_rslt_full_eew16_d1[i*2+j][13:0]) || mul_rslt_full_eew16_d1[i*2+j][15]) : //RNE
474	                                                                mul_rslt_full_eew16_d1[i*2+j][14]; //RNU
475	      vsmul_rslt_eew16_d1[16*(i*2+j) +:16]= mul_rslt_full_eew16_d1[i*2+j][31:30] == 2'b01 ? 16'h7fff : //saturate
476	                                                                                       mul_rslt_full_eew16_d1[i*2+j][15+:16] + {15'b0,vsmul_round_incr_eew16_d1[i*2+j]};//right shift 15bit then +"1"
477	      vsmul_sat_eew16_d1[i*2+j] = mul_rslt_full_eew16_d1[i*2+j][31:30] == 2'b01;
478	    end
479	  end
480	end
481	assign mul_rslt_eew16_d1 = is_vsmul_d1     ? vsmul_rslt_eew16_d1 : //vsmul
482	                           mul_is_widen_d1 ? mul_rslt_eew16_widen_d1[`VLEN-1:0] : //widen
483	                                             mul_rslt_eew16_no_widen_d1; //normal
484	assign update_vxsat_eew16_d1 = {vsmul_sat_eew16_d1[7],1'b0,
485	                                vsmul_sat_eew16_d1[6],1'b0,
486	                                vsmul_sat_eew16_d1[5],1'b0,
487	                                vsmul_sat_eew16_d1[4],1'b0,
488	                                vsmul_sat_eew16_d1[3],1'b0,
489	                                vsmul_sat_eew16_d1[2],1'b0,
490	                                vsmul_sat_eew16_d1[1],1'b0,
491	                                vsmul_sat_eew16_d1[0],1'b0};
492	//eew32
493	//full rslt is 64bit
494	always@(*) begin
495	  for (i=0; i<4; i=i+1) begin //z
496	    mul_rslt_full_eew32_d1[i] = {mul8_out_d1[i*16+15],48'b0} + 
497	                             {{8{mul8_out_d1[i*16+14][15]&&mul_src1_is_signed_d1}},mul8_out_d1[i*16+14],40'b0} + 
498	                             {{8{mul8_out_d1[i*16+11][15]&&mul_src2_is_signed_d1}},mul8_out_d1[i*16+11],40'b0} + 
499	                             {{16{mul8_out_d1[i*16+13][15]&&mul_src1_is_signed_d1}},mul8_out_d1[i*16+13],32'b0} + 
500	                             {16'b0,mul8_out_d1[i*16+10],32'b0} + 
501	                             {{16{mul8_out_d1[i*16+7][15]&&mul_src2_is_signed_d1}},mul8_out_d1[i*16+7],32'b0} + 
502	                             {{24{mul8_out_d1[i*16+12][15]&&mul_src1_is_signed_d1}},mul8_out_d1[i*16+12],24'b0} + 
503	                             {24'b0,mul8_out_d1[i*16+9],24'b0} +
504	                             {24'b0,mul8_out_d1[i*16+6],24'b0} + 
505	                             {{24{mul8_out_d1[i*16+3][15]&&mul_src2_is_signed_d1}},mul8_out_d1[i*16+3],24'b0} + 
506	                             {32'b0,mul8_out_d1[i*16+8],16'b0} + 
507	                             {32'b0,mul8_out_d1[i*16+5],16'b0} +
508	                             {32'b0,mul8_out_d1[i*16+2],16'b0} + 
509	                             {40'b0,mul8_out_d1[i*16+4],8'b0} + 
510	                             {40'b0,mul8_out_d1[i*16+1],8'b0} + 
511	                             {48'b0,mul8_out_d1[i*16]};
512	    mul_rslt_eew32_widen_d1[64*i +: 64] = mul_rslt_full_eew32_d1[i];//widen, and convert to [255:0]
513	    mul_rslt_eew32_no_widen_d1[32*i +: 32] = mul_keep_low_bits_d1 ? mul_rslt_full_eew32_d1[i][31:0] : mul_rslt_full_eew32_d1[i][63:32];
514	    //Below are for rounding mul (vsmul.vv, vsmul.vx)
515	    //right shift bit is 32-1=31 not 32 !
516	    //(TODO) Improve to make this readable
517	    vsmul_round_incr_eew32_d1[i] = mul_uop_xrm_d1==2'd3 ? !mul_rslt_full_eew32_d1[i][31] && (|mul_rslt_full_eew32_d1[i][30:0]) : //ROD
518	                                   mul_uop_xrm_d1==2'd2 ? 1'b0  : //RDN
519	                                   mul_uop_xrm_d1==2'd1 ? mul_rslt_full_eew32_d1[i][30] && (|(mul_rslt_full_eew32_d1[i][29:0]) || mul_rslt_full_eew32_d1[i][31]) : //RNE
520	                                                          mul_rslt_full_eew32_d1[i][30]; //RNU      
521	    vsmul_rslt_eew32_d1[32*i +:32]= mul_rslt_full_eew32_d1[i][63:62] == 2'b01 ? 32'h7fff_ffff : //saturate
522	                                                                             mul_rslt_full_eew32_d1[i][31+:32] + {31'b0,vsmul_round_incr_eew32_d1[i]};//right shift 31bit then +"1"
523	    vsmul_sat_eew32_d1[i] = mul_rslt_full_eew32_d1[i][63:62] == 2'b01;
524	  end
525	end
526	assign mul_rslt_eew32_d1 = is_vsmul_d1     ? vsmul_rslt_eew32_d1 : //vsmul
527	                           mul_is_widen_d1 ? mul_rslt_eew32_widen_d1[`VLEN-1:0] : //widen
528	                                             mul_rslt_eew32_no_widen_d1; //normal
529	assign update_vxsat_eew32_d1 = {vsmul_sat_eew32_d1[3],3'b0,
530	                                vsmul_sat_eew32_d1[2],3'b0,
531	                                vsmul_sat_eew32_d1[1],3'b0,
532	                                vsmul_sat_eew32_d1[0],3'b0};
533	
534	//Output pack
535	assign mul2rob_uop_valid = rs2mul_uop_valid_d1;
536	
537	assign mul2rob_uop_data.rob_entry = mul_uop_rob_entry_d1;
538	assign mul2rob_uop_data.w_data = mul_top_vs_eew_d1==EEW32 ? mul_rslt_eew32_d1 : 
539	                                 mul_top_vs_eew_d1==EEW16 ? mul_rslt_eew16_d1 :
540	                                                            mul_rslt_eew8_d1; //all possible cases are 8/16/32
541	assign mul2rob_uop_data.w_valid = rs2mul_uop_valid_d1;
542	assign mul2rob_uop_data.vsaturate = is_vsmul_d1 ? mul_top_vs_eew_d1==EEW32 ? update_vxsat_eew32_d1 :
543	                                                  mul_top_vs_eew_d1==EEW16 ? update_vxsat_eew16_d1 :
544	                                                                             update_vxsat_eew8_d1  :
545	                                                                             {`VLENB{1'b0}};
546	
547	`ifdef TB_SUPPORT
548	assign mul2rob_uop_data.uop_pc = mul_uop_pc_d1;
549	`endif
550	endmodule
