751	// After mac, calculte eew8, eew16, eew32 results
752	//eew8
753	//full rslt is 16bit
754	always@(*) begin
755	  for (i=0; i<`VLENW; i=i+1) begin: tiles_eew8
756	    for (j=0; j<`WORD_WIDTH/`BYTE_WIDTH; j=j+1) begin // 
757	      mac_rslt_full_eew8_d1[i*4+j]                                   = mac8_out_d1[i*16+j*5];
758	      mac_rslt_eew8_widen_d1[2*`BYTE_WIDTH*(i*4+j) +: 2*`BYTE_WIDTH] = mac_rslt_full_eew8_d1[i*4+j];//widen, and convert to [255:0]
759	      mac_rslt_eew8_no_widen_d1[`BYTE_WIDTH*(i*4+j) +: `BYTE_WIDTH]  = mac_keep_low_bits_d1 ? 
760	                                                                       mac_rslt_full_eew8_d1[i*4+j][0          +:`BYTE_WIDTH] : 
761	                                                                       mac_rslt_full_eew8_d1[i*4+j][`BYTE_WIDTH+:`BYTE_WIDTH];
762	      //Below are for rounding mul (vsmul.vv, vsmul.vx)
763	      //right shift bit is 7 not 8 !
764	      case(mac_uop_xrm_d1)
765	        ROD: vsmul_round_incr_eew8_d1[i*4+j] = !mac_rslt_full_eew8_d1[i*4+j][7] && (|mac_rslt_full_eew8_d1[i*4+j][6:0]);
766	        RDN: vsmul_round_incr_eew8_d1[i*4+j] = 'b0; 
767	        RNE: begin 
768	             vsmul_round_incr_eew8_d1[i*4+j] = mac_rslt_full_eew8_d1[i*4+j][6] && 
769	                                               ( (|mac_rslt_full_eew8_d1[i*4+j][5:0]) || mac_rslt_full_eew8_d1[i*4+j][7] );
770	        end
771	        //RNU
772	        default: vsmul_round_incr_eew8_d1[i*4+j] = mac_rslt_full_eew8_d1[i*4+j][6];
773	      endcase
774	      
775	      // saturating
776	      vsmul_sat_eew8_d1[i*4+j] = mac_rslt_full_eew8_d1[i*4+j][15:14] == 2'b01;
777	      vsmul_rslt_eew8_d1[`BYTE_WIDTH*(i*4+j)+:`BYTE_WIDTH] = vsmul_sat_eew8_d1[i*4+j] ? 8'h7f : //saturate 
778	                                   //right shift 7bit then +"1"
779	                                   mac_rslt_full_eew8_d1[i*4+j][(`BYTE_WIDTH-1)+:`BYTE_WIDTH] + {7'b0,vsmul_round_incr_eew8_d1[i*4+j]};
780	
781	      //Below are for vmac related instructions
782	      vmac_mul_add_eew8_no_widen_d1[i*4+j] = {1'b0,mac_addsrc_d1[            `BYTE_WIDTH*(i*4+j) +: `BYTE_WIDTH]} + 
783	                                             {1'b0,mac_rslt_eew8_no_widen_d1[`BYTE_WIDTH*(i*4+j) +: `BYTE_WIDTH]} ; //9bit
784	      vmac_mul_sub_eew8_no_widen_d1[i*4+j] = {1'b0,mac_addsrc_d1[            `BYTE_WIDTH*(i*4+j) +: `BYTE_WIDTH]} - 
785	                                             {1'b0,mac_rslt_eew8_no_widen_d1[`BYTE_WIDTH*(i*4+j) +: `BYTE_WIDTH]} ;
786	      vmac_rslt_eew8_no_widen_d1[`BYTE_WIDTH*(i*4+j) +: `BYTE_WIDTH] = mac_mul_reverse_d1 ? 
787	                                                                         vmac_mul_sub_eew8_no_widen_d1[i*4+j][`BYTE_WIDTH-1:0] :
788	                                                                         vmac_mul_add_eew8_no_widen_d1[i*4+j][`BYTE_WIDTH-1:0] ;
789	
790	      vmac_mul_add_eew8_widen_d1[i*4+j] = {1'b0,mac_addsrc_widen_d1[   2*`BYTE_WIDTH*(i*4+j) +: 2*`BYTE_WIDTH]} + 
791	                                          {1'b0,mac_rslt_eew8_widen_d1[2*`BYTE_WIDTH*(i*4+j) +: 2*`BYTE_WIDTH]} ; //17bit
792	      vmac_mul_sub_eew8_widen_d1[i*4+j] = {1'b0,mac_addsrc_widen_d1[   2*`BYTE_WIDTH*(i*4+j) +: 2*`BYTE_WIDTH]} - 
793	                                          {1'b0,mac_rslt_eew8_widen_d1[2*`BYTE_WIDTH*(i*4+j) +: 2*`BYTE_WIDTH]} ;
794	      vmac_rslt_eew8_widen_d1[`HWORD_WIDTH*(i*4+j) +: `HWORD_WIDTH] = mac_mul_reverse_d1 ? 
795	                                                                        vmac_mul_sub_eew8_widen_d1[i*4+j][2*`BYTE_WIDTH-1:0] :
796	                                                                        vmac_mul_add_eew8_widen_d1[i*4+j][2*`BYTE_WIDTH-1:0] ;
797	    end
798	  end
799	end
