857	                                                                           vmac_mul_sub_eew16_no_widen_d1[i*2+j][`HWORD_WIDTH-1:0] :
858	                                                                           vmac_mul_add_eew16_no_widen_d1[i*2+j][`HWORD_WIDTH-1:0] ;
