864	      vmac_rslt_eew16_widen_d1[`WORD_WIDTH*(i*2+j) +: `WORD_WIDTH] = mac_mul_reverse_d1 ? 
865	                                                                       vmac_mul_sub_eew16_widen_d1[i*2+j][2*`HWORD_WIDTH-1:0] :
