939	    vmac_mul_sub_eew32_widen_d1[i] = {1'b0,mac_addsrc_widen_d1[    2*`WORD_WIDTH*i +: 2*`WORD_WIDTH]} - 
940	                                     {1'b0,mac_rslt_eew32_widen_d1[2*`WORD_WIDTH*i +: 2*`WORD_WIDTH]} ;
941	    vmac_rslt_eew32_widen_d1[64*i +: 64] = mac_mul_reverse_d1 ? vmac_mul_sub_eew32_widen_d1[i][2*`WORD_WIDTH-1:0] :
942	                                                                vmac_mul_add_eew32_widen_d1[i][2*`WORD_WIDTH-1:0] ;
943	  end
944	end
945	
946	always_comb begin
947	  casex({is_vmac_d1,mac_is_widen_d1,is_vsmul_d1,mac_is_widen_d1})
948	    4'b11?? : mac_rslt_eew32_d1 = vmac_rslt_eew32_widen_d1[`VLEN-1:0];  //mac widen 
949	    4'b10?? : mac_rslt_eew32_d1 = vmac_rslt_eew32_no_widen_d1;          //mac normal
950	    4'b0?1? : mac_rslt_eew32_d1 = vsmul_rslt_eew32_d1;                  //vsmul
951	    4'b0?01 : mac_rslt_eew32_d1 = mac_rslt_eew32_widen_d1[`VLEN-1:0];   //mul widen
952	    4'b0?00 : mac_rslt_eew32_d1 = mac_rslt_eew32_no_widen_d1;           //mul normal
953	    default : mac_rslt_eew32_d1 = 'b0;
954	  endcase
955	end
956	
957	always_comb begin
958	  for(int i=0;i<`VLENW;i++) begin
959	    update_vxsat_eew32_d1[4*i +: 4] = {vsmul_sat_eew32_d1[i],3'b0}; 
960	  end
961	end
962	
963	//Output pack
964	`ifdef TB_SUPPORT
965	  assign mac2rob_uop_data.uop_pc    = mac_uop_pc_d1;
966	`endif
967	  assign mac2rob_uop_valid          = rs2mac_uop_valid_d1;
968	  assign mac2rob_uop_data.rob_entry = mac_uop_rob_entry_d1;
969	  assign mac2rob_uop_data.w_valid   = rs2mac_uop_valid_d1;
970	  assign mac2rob_uop_data.vsaturate = is_vsmul_d1 ? update_vxsat : 'b0;
971	`ifdef ZVE32F_ON
972	  assign mac2rob_uop_data.fpexp     = 'b0;
973	`endif
974	
975	always_comb begin
976	  case(mac_top_vs_eew_d1)
977	    EEW32: begin
978	      mac2rob_uop_data.w_data = mac_rslt_eew32_d1; 
979	      update_vxsat            = update_vxsat_eew32_d1;
980	    end
981	    EEW16: begin
982	      mac2rob_uop_data.w_data = mac_rslt_eew16_d1; 
983	      update_vxsat            = update_vxsat_eew16_d1;
984	    end
985	    default: begin  // EEW8
986	      mac2rob_uop_data.w_data = mac_rslt_eew8_d1; 
987	      update_vxsat            = update_vxsat_eew8_d1;
988	    end
989	  endcase
990	end
991	
992	
993	endmodule
994

